import React, { useEffect, useState } from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Swal from 'sweetalert2';
import Navbar from './components/Navbar';
import ProtectedRoute from './components/ProtectedRoute';
import Katalog from './pages/Katalog';
import DetailProduk from './pages/DetailProduk';
import Keranjang from './pages/Keranjang';
import Login from './pages/Login';
import DashboardAdmin from './pages/DashboardAdmin';

const TOKEN_KEY = 'campbread_token';

function App() {
  const [kataKunci, setKataKunci] = useState('');
  const [keranjang, setKeranjang] = useState([]);
  const [isLoggedIn, setIsLoggedIn] = useState(Boolean(localStorage.getItem(TOKEN_KEY)));

  useEffect(() => {
    setIsLoggedIn(Boolean(localStorage.getItem(TOKEN_KEY)));
  }, []);

  const tambahKeKeranjang = (produk, qty = 1) => {
    const itemCart = {
      ...produk,
      id: produk.id,
      nama: produk.name ?? produk.nama,
      harga: produk.price ? `Rp ${Number(produk.price).toLocaleString('id-ID')}` : produk.harga,
      img: produk.imageUrl ?? produk.img
    };

    const adaDiKeranjang = keranjang.find((item) => item.id === itemCart.id);
    if (adaDiKeranjang) {
      setKeranjang(keranjang.map((item) =>
        item.id === itemCart.id ? { ...adaDiKeranjang, jumlah: adaDiKeranjang.jumlah + qty } : item
      ));
    } else {
      setKeranjang([...keranjang, { ...itemCart, jumlah: qty }]);
    }

    Swal.fire({
      icon: 'success',
      title: 'Berhasil!',
      text: `${qty} ${itemCart.nama} telah masuk keranjang.`,
      showConfirmButton: false,
      timer: 1500,
      toast: true,
      position: 'top-end'
    });
  };

  return (
    <Router>
      <Navbar setKataKunci={setKataKunci} jumlahKeranjang={keranjang.length} />
      <Routes>
        <Route path="/" element={<Katalog kataKunci={kataKunci} tambahKeKeranjang={tambahKeKeranjang} />} />
        <Route path="/produk/:id" element={<DetailProduk tambahKeKeranjang={tambahKeKeranjang} />} />
        <Route path="/keranjang" element={<Keranjang keranjang={keranjang} setKeranjang={setKeranjang} isLoggedIn={isLoggedIn} />} />
        <Route path="/login" element={<Login setIsLoggedIn={setIsLoggedIn} />} />
        <Route
          path="/admin"
          element={
            <ProtectedRoute isAllowed={isLoggedIn}>
              <DashboardAdmin setIsLoggedIn={setIsLoggedIn} />
            </ProtectedRoute>
          }
        />
      </Routes>
    </Router>
  );
}

export default App;
